import hashlib
from typing import List

class MerkleTree:
    def __init__(self, height: int):
        self.height = height
        self.num_leaves = 2 ** height
        self.levels = []

    def hash(self, data: bytes) -> bytes:
        return hashlib.sha256(data).digest()

    def build(self, leaves: List[bytes]) -> bytes:
        self.levels = [leaves]
        current = leaves
        for _ in range(self.height):
            next_level = []
            for i in range(0, len(current), 2):
                combined = self.hash(current[i] + current[i+1])
                next_level.append(combined)
            self.levels.append(next_level)
            current = next_level
        return current[0]

    def get_auth_path(self, leaf_idx: int) -> List[bytes]:
        path = []
        idx = leaf_idx
        for level in range(self.height):
            sibling_idx = idx ^ 1
            path.append(self.levels[level][sibling_idx])
            idx //= 2
        return path

    def verify(self, leaf: bytes, idx: int, path: List[bytes], root: bytes) -> bool:
        current = leaf
        for sibling in path:
            if idx % 2 == 0:
                current = self.hash(current + sibling)
            else:
                current = self.hash(sibling + current)
            idx //= 2
        return current == root

import hashlib
import secrets
from typing import Optional, Tuple, List

class MSS:
    def __init__(self, height: int = 4):
        self.height = height
        self.state = 0
        self.ots_sks = []
        self.ots_pks = []
        self.tree = None
        self.root = None

    def _hash(self, data: bytes) -> bytes:
        return hashlib.sha256(data).digest()

    def _ots_keygen(self):
        sk = [secrets.token_bytes(32) for _ in range(32)]
        pk = [self._hash(s) for s in sk]
        return sk, self._hash(b''.join(pk))

    def _ots_sign(self, sk, msg):
        h = self._hash(msg)
        return [sk[i] if (h[i//8]>>(7-i%8))&1 else self._hash(sk[i]) for i in range(32)]

    def _ots_verify(self, pk_hash, msg, sig):
        h = self._hash(msg)
        pk = [self._hash(sig[i]) if (h[i//8]>>(7-i%8))&1 else sig[i] for i in range(32)]
        return self._hash(b''.join(pk)) == pk_hash

    def keygen(self) -> bytes:
        for _ in range(2**self.height):
            sk, pk = self._ots_keygen()
            self.ots_sks.append(sk)
            self.ots_pks.append(pk)

        self.tree = MerkleTree(self.height)
        self.root = self.tree.build(self.ots_pks)
        return self.root

    def sign(self, message: bytes) -> Optional[dict]:
        if self.state >= 2**self.height:
            return None
        idx = self.state
        self.state += 1
        ots_sig = self._ots_sign(self.ots_sks[idx], message)
        path = self.tree.get_auth_path(idx)
        return {'idx': idx, 'ots_pk': self.ots_pks[idx], 'ots_sig': ots_sig, 'path': path}

    def verify(self, pk: bytes, message: bytes, sig: dict) -> bool:
        if not self._ots_verify(sig['ots_pk'], message, sig['ots_sig']):
            return False
        return self.tree.verify(sig['ots_pk'], sig['idx'], sig['path'], pk)

