exercises.solution:
from typing import List, Set

class StateAnalyzer:
    def __init__(self, max_signatures: int):
        self.max_signatures = max_signatures
        self.used_indices = set()
        self.history = []

    def record_signature(self, idx: int) -> bool:
        reuse = idx in self.used_indices
        self.used_indices.add(idx)
        self.history.append(idx)
        return reuse

    def get_remaining(self) -> int:
        return self.max_signatures - len(self.used_indices)

    def simulate_backup_restore(self, restore_point: int) -> Set[int]:
        if restore_point >= len(self.history):
            return set()
        at_risk = set(self.history[restore_point:])
        return at_risk

