class MSSSize:
    def __init__(self, height: int, hash_bytes: int, ots_sig_elements: int):
        self.height = height
        self.hash_bytes = hash_bytes
        self.ots_elements = ots_sig_elements

    def signature_size(self) -> int:
        # OTS signature + OTS pk hash + auth path + index
        return (self.ots_elements * self.hash_bytes + 
                self.hash_bytes + 
                self.height * self.hash_bytes + 
                (self.height + 7) // 8)

    def public_key_size(self) -> int:
        return self.hash_bytes

    def total_private_key_size(self) -> int:
        num_leaves = 2 ** self.height
        return num_leaves * self.ots_elements * self.hash_bytes
